targets.expr:
count by (helm_sh_chart) (
  up{namespace="$namespace",pod=~"$app.*",helm_sh_chart!=""}
) or label_replace(
  count by (label_helm_sh_chart) (
    kube_pod_labels{namespace="$namespace",pod=~"$app.*",label_helm_sh_chart!=""}
  ),
  "helm_sh_chart", "$1", "label_helm_sh_chart", "(.*)"
)

count by (app_kubernetes_io_version) (
  up{namespace="$namespace",pod=~"$app.*",app_kubernetes_io_version!=""}
) or label_replace(
  count by (label_app_kubernetes_io_version) (
    kube_pod_labels{namespace="$namespace",pod=~"$app.*",label_app_kubernetes_io_version!=""}
  ),
  "app_kubernetes_io_version", "$1", "label_app_kubernetes_io_version", "(.*)"
)

topk(
  15,
  sum by (method, uri) (
    rate(http_server_requests_seconds_sum{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[5m])
  )
  /
  clamp_min(
    sum by (method, uri) (
      rate(http_server_requests_seconds_count{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[5m])
    ),
    1e-9
  )
)

topk(
  15,
  (
    histogram_quantile(
      0.95,
      sum by (method, uri, le) (
        rate(http_server_requests_seconds_bucket{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[5m])
      )
    )
  )
  or
  (
    sum by (method, uri) (
      rate(http_server_requests_seconds_sum{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[5m])
    )
    /
    clamp_min(
      sum by (method, uri) (
        rate(http_server_requests_seconds_count{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[5m])
      ),
      1e-9
    )
  )
)

sum by (api) (
  label_join(
    sum by (method, uri) (
      increase(http_server_requests_seconds_count{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[$__range])
    ),
    "api", " ", "method", "uri"
  )
)

(
  sum by (api) (
    label_join(
      sum by (method, uri) (
        increase(http_server_requests_seconds_count{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*",status=~"2.."}[$__range])
      ),
      "api", " ", "method", "uri"
    )
  )
) or (
  sum by (api) (
    label_join(
      sum by (method, uri) (
        increase(http_server_requests_seconds_count{application="$application",namespace="$namespace",method=~"$method",uri=~"$uri",uri!~".*actuator.*"}[$__range])
      ),
      "api", " ", "method", "uri"
    )
  ) * 0
)

